19	use arrow::datatypes::SchemaRef;
20	use dashmap::DashSet;
21	use datafusion::common::{DataFusionError, Result as DataFusionResult};
22	use datafusion::logical_expr::{Expr, LogicalPlan, UserDefinedLogicalNodeCore};
23	use datafusion::physical_expr::{Distribution, PhysicalExpr};
24	use datafusion::physical_plan::{
25	    DisplayAs, DisplayFormatType, ExecutionPlan, RecordBatchStream, SendableRecordBatchStream,
26	};
27	use futures::{Stream, StreamExt};
28	
