35	pub(crate) type BarrierSurvivorSet = Arc<DashSet<String>>;
36	
37	#[derive(Debug)]
38	/// Physical Node for the MergeBarrier
39	/// Batches to this node must be repartitioned on col('deleta_rs_path').
40	/// Each record batch then undergoes further partitioning based on the file column to it's corresponding barrier
41	pub struct MergeBarrierExec {
42	    input: Arc<dyn ExecutionPlan>,
43	    file_column: Arc<String>,
44	    survivors: BarrierSurvivorSet,
45	    expr: Arc<dyn PhysicalExpr>,
46	}
47	
48	impl MergeBarrierExec {
49	    /// Create a new MergeBarrierExec Node
50	    pub fn new(
51	        input: Arc<dyn ExecutionPlan>,
52	        file_column: Arc<String>,
53	        expr: Arc<dyn PhysicalExpr>,
54	    ) -> Self {
55	        MergeBarrierExec {
56	            input,
57	            file_column,
58	            survivors: Arc::new(DashSet::new()),
59	            expr,
60	        }
61	    }
62	
63	    /// Files that have modifications to them and need to removed from the delta log
