    #[tokio::test]
    async fn test_merge_rewrite_removes_old_file_for_partition_value_with_space() {
        let schema = Arc::new(ArrowSchema::new(vec![
            Field::new("group", ArrowDataType::Utf8, false),
            Field::new("region", ArrowDataType::Utf8, false),
            Field::new(
                "ts",
                ArrowDataType::Timestamp(TimeUnit::Microsecond, None),
                false,
            ),
            Field::new("val", ArrowDataType::Float64, false),
        ]));
        let batch = RecordBatch::try_new(
            Arc::clone(&schema),
            vec![
                Arc::new(arrow::array::StringArray::from(vec![
                    "foo bar", "foo bar", "foo bar",
                ])),
                Arc::new(arrow::array::StringArray::from(vec!["A", "B", "C"])),
                Arc::new(arrow::array::TimestampMicrosecondArray::from(vec![
                    1_704_067_200_000_000,
                    1_704_067_200_000_000,
                    1_704_067_200_000_000,
                ])),
                Arc::new(arrow::array::Float64Array::from(vec![1.0, 2.0, 3.0])),
            ],
        )
        .unwrap();

        let table = DeltaTable::new_in_memory()
            .create()
            .with_columns(StructType::try_from(schema.as_ref()).unwrap().fields().cloned())
            .with_partition_columns(["group"])
            .await
            .unwrap();

        let predicate = col("target.group")
            .eq(lit("foo bar"))
            .and(col("target.region").eq(col("source.region")))
            .and(col("target.ts").eq(col("source.ts")));

        let mut table = table;
        for expected_removed in [0, 1] {
            let ctx = SessionContext::new();
            let source = ctx.read_batch(batch.clone()).unwrap();
            let (merged, metrics) = table
                .merge(source, predicate.clone())
                .with_source_alias("source")
                .with_target_alias("target")
                .when_matched_update_all(None)
                .unwrap()
                .when_not_matched_insert_all(None)
                .unwrap()
                .await
                .unwrap();

            assert_eq!(metrics.num_target_files_removed, expected_removed);

            let actual = get_data(&merged).await;
            let row_count: usize = actual.iter().map(|batch| batch.num_rows()).sum();
            assert_eq!(row_count, 3);
            table = merged;
        }
    }

    #[tokio::test]
    async fn test_merge_rewrite_removes_old_file_and_avoids_duplicate_rows() {
        let (table, source) = setup().await;
        let original_paths: Vec<String> = table
            .snapshot()
            .unwrap()
            .log_data()
            .into_iter()
            .map(|add| add.path().to_string())
            .collect();
        assert!(!original_paths.is_empty());

        let (table, metrics) = table
            .merge(source, col("target.id").eq(col("source.id")))
            .with_source_alias("source")
            .with_target_alias("target")
            .when_matched_update(|update| {
                update
                    .update("value", col("source.value"))
                    .update("modified", col("source.modified"))
            })
            .unwrap()
            .when_not_matched_insert(|insert| {
                insert
                    .set("id", col("source.id"))
                    .set("value", col("source.value"))
                    .set("modified", col("source.modified"))
            })
            .unwrap()
            .await
            .unwrap();

        assert!(metrics.num_target_files_added >= 1);
        assert!(metrics.num_target_files_removed >= 1);

        let snapshot_bytes = table
            .log_store
            .read_commit_entry(2)
            .await
            .unwrap()
            .expect("failed to get snapshot bytes");
        let actions = crate::logstore::get_actions(2, &snapshot_bytes).unwrap();
        let removed_paths: Vec<_> = actions
            .iter()
            .filter_map(|action| match action {
                Action::Remove(remove) => Some(remove.path.clone()),
                _ => None,
            })
            .collect();
        assert!(!removed_paths.is_empty());
        assert!(
            original_paths
                .iter()
                .any(|path| removed_paths.contains(path)),
            "Expected at least one rewritten source file to be removed",
        );

        let table_for_query =
            DeltaTable::new_with_state(table.log_store.clone(), table.snapshot().unwrap().clone());
        let ctx = SessionContext::new();
        table_for_query
            .update_datafusion_session(&ctx.state())
            .unwrap();
        ctx.register_table("test", table_for_query.table_provider().await.unwrap())
            .unwrap();
        let duplicate_rows = ctx
            .sql(
                "SELECT id, value, modified, COUNT(*) AS cnt \
                 FROM test \
                 GROUP BY id, value, modified \
                 HAVING cnt > 1",
            )
            .await
            .unwrap()
            .collect()
            .await
            .unwrap();
        let duplicate_count: usize = duplicate_rows.iter().map(|batch| batch.num_rows()).sum();
        assert_eq!(
            duplicate_count, 0,
            "Expected merge output without duplicate rows"
        );
    }

